// Define a function to validate the table structure
function validateTable(htmlString) {
    var parser = new DOMParser();
    var doc = parser.parseFromString(htmlString, 'text/html');
    var tables = doc.getElementsByTagName('table');
    for (var i = 0; i < tables.length; i++) {
        var table = tables[i];
        var thead = table.getElementsByTagName('thead')[0];
        var tbody = table.getElementsByTagName('tbody')[0];
        if (thead && tbody) {
            var rows = thead.getElementsByTagName('tr');
            var rows2 = tbody.getElementsByTagName('tr');
            for (var j = 0; j < rows.length; j++) {
                var ths = rows[j].getElementsByTagName('th');
                var tds = rows[j].getElementsByTagName('td');
                if (ths.length > tds.length) {
                    return 'Valid';
                }
            }
            for (var j = 0; j < rows2.length; j++) {
                var ths = rows2[j].getElementsByTagName('th');
                var tds = rows2[j].getElementsByTagName('td');
                if (ths.length > tds.length) {
                    return 'Error: Invalid heading structure - <th> elements must come before <td> elements';
                }
            }
        }
    }
    return 'Valid';
}

