class Solution:
    def validate_table(self, html_string: str) -> str:
        from bs4 import BeautifulSoup
        soup = BeautifulSoup(html_string, 'html.parser')
        tables = soup.find_all('table')
        for table in tables:
            thead = table.find('thead')
            tbody = table.find('tbody')
            if thead and tbody:
                rows = thead.find_all('tr')
                rows2 = tbody.find_all('tr')
                for row in rows:
                    ths = row.find_all('th')
                    tds = row.find_all('td')
                    if len(ths) > len(tds):
                        return 'Valid'
                for row in rows2:
                    ths = row.find_all('th')
                    tds = row.find_all('td')
                    if len(ths) > len(tds):
                        return 'Error: Invalid heading structure - <th> elements must come before <td> elements'
        return 'Valid'

